const msg = $input.first().json.message;
const from_id = msg.from.id;
const text = (msg.text || '').trim().toUpperCase();
const PREM_ID = 7731591925;

if (from_id !== PREM_ID) return [];

const parts = text.split(' ');
if (parts.length !== 2) return [];
const action = parts[0]; // APPROVE or REJECT
const target_id = parseInt(parts[1]);

if (!['APPROVE','REJECT'].includes(action) || isNaN(target_id)) return [];

return [{ json: { action, target_id, from_id } }];
